-- Repairs the mojibake introduced by previous migrations (supabase db push
-- corrupts UTF-8 on Windows) and writes the correct final content.
-- Content is embedded as ASCII base64 and decoded server-side -> immune to the
-- push encoding bug. Adds the rule of one image prompt per carousel slide.

UPDATE modules SET content = convert_from(decode('', 'base64'), 'UTF8')
WHERE slug = 'template-prompt-imagem';

UPDATE modules SET content = convert_from(decode('', 'base64'), 'UTF8')
WHERE slug = 'regras-post-instagram';
